import React from 'react'
import DocumentTable from '../../../../components/academic/DocumentTable'

interface Props { params: { id: string } }

export default function TeacherStudentDocumentsPage({ params }: Props) {
  return (
    <div className="p-6">
      <h1 className="text-2xl font-bold mb-4">Student Documents</h1>
      {/* @ts-expect-error server -> client */}
      <DocumentTable studentId={params.id} />
    </div>
  )
}
"use client";

import { useState, useEffect } from "react";
import { AcademicDocumentsService } from "@/services/service_academic_documents";
import { AcademicDocument } from "@/models/academic_document.model";
import { DocumentTable } from "@/components/academic-documents/DocumentTable";
import { DocumentFilters } from "@/components/academic-documents/DocumentFilters";
import { DocumentPreviewModal } from "@/components/academic-documents/DocumentPreviewModal";
import { useToast } from "@/components/ui/use-toast";
import { useParams } from "next/navigation";

export default function TeacherStudentDocumentsPage() {
  const params = useParams();
  const studentId = params.id as string;

  const [documents, setDocuments] = useState<AcademicDocument[]>([]);
  const [filteredDocuments, setFilteredDocuments] = useState<AcademicDocument[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState("");
  const [typeFilter, setTypeFilter] = useState("all");
  const [statusFilter, setStatusFilter] = useState("all");

  const [isPreviewOpen, setIsPreviewOpen] = useState(false);
  const [selectedDocument, setSelectedDocument] = useState<AcademicDocument | null>(null);

  const { toast } = useToast();

  useEffect(() => {
    if (studentId) {
      loadDocuments();
    }
  }, [studentId]);

  useEffect(() => {
    filterDocuments();
  }, [documents, searchQuery, typeFilter, statusFilter]);

  const loadDocuments = async () => {
    setLoading(true);
    try {
      const docs = await AcademicDocumentsService.getDocumentsForStudent(studentId);
      setDocuments(docs);
    } catch (error) {
      toast({
        title: "Error",
        description: "Failed to load documents.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const filterDocuments = () => {
    let filtered = [...documents];

    if (searchQuery) {
      const query = searchQuery.toLowerCase();
      filtered = filtered.filter((doc) =>
        doc.type.toLowerCase().includes(query)
      );
    }

    if (typeFilter !== "all") {
      filtered = filtered.filter((doc) => doc.type === typeFilter);
    }

    if (statusFilter !== "all") {
      filtered = filtered.filter((doc) => doc.status === statusFilter);
    }

    setFilteredDocuments(filtered);
  };

  const handlePreview = (doc: AcademicDocument) => {
    setSelectedDocument(doc);
    setIsPreviewOpen(true);
  };

  const handleDownload = (doc: AcademicDocument) => {
    if (doc.fileUrl) {
      window.open(doc.fileUrl, "_blank");
    } else {
      toast({
        title: "Error",
        description: "File not available.",
        variant: "destructive",
      });
    }
  };

  return (
    <div className="container mx-auto py-8 space-y-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Student Documents</h1>
          <p className="text-muted-foreground">
            View official documents for student ID: <span className="font-mono">{studentId}</span>
          </p>
        </div>
      </div>

      <DocumentFilters
        onSearchChange={setSearchQuery}
        onTypeChange={setTypeFilter}
        onStatusChange={setStatusFilter}
        showStudentFilter={false}
      />

      {loading ? (
        <div className="flex justify-center py-8">Loading...</div>
      ) : (
        <DocumentTable
          documents={filteredDocuments}
          role="teacher"
          onPreview={handlePreview}
          onDownload={handleDownload}
        />
      )}

      <DocumentPreviewModal
        open={isPreviewOpen}
        onOpenChange={setIsPreviewOpen}
        document={selectedDocument}
      />
    </div>
  );
}
